html:
{% set company = frappe.get_doc('Company', doc.company) if doc.company else None %}
{% set owner_name = frappe.db.get_value('User', doc.owner, 'full_name') or doc.owner or '' %}
{% set _ca_link = doc.company_address or None %}
{% if company and not _ca_link %}
{% set _ca_link = frappe.call('erpnext.setup.doctype.company.company.get_default_company_address', name=company.name) %}
{% endif %}
{% set company_addr = frappe.get_doc('Address', _ca_link) if _ca_link else None %}
{% set ship_addr_doc = frappe.get_doc('Address', doc.shipping_address_name) if doc.get('shipping_address_name') else None %}
{% set billing_addr_doc = frappe.get_doc('Address', doc.customer_address) if doc.get('customer_address') else None %}

<!-- ============================================== -->
<!-- ADVANCED JINJA ADDRESS CLEANSER (FIXED COMMAS) -->
<!-- ============================================== -->

<!-- 1. CLEAN COMPANY ADDRESS -->
{% set raw_ca = (company_addr.get_display() if company_addr else '') or doc.get('company_address_display') or (company.address_html if company else '') or '' %}
{% set text_ca = raw_ca | string | replace('<br>', '\n') | replace('<br/>', '\n') | replace('<br />', '\n') | striptags %}
{% set ns_ca = namespace(lines=[]) %}
{% for line in text_ca.splitlines() %}
  {% set cl = line.strip().strip(',') %}
  {% if cl %}{% set _ = ns_ca.lines.append(cl) %}{% endif %}
{% endfor %}
{% set company_address_compact = ns_ca.lines | join(', ') %}

<!-- 2. CLEAN BILLING ADDRESS -->
{% set raw_bill = doc.address_display or '' %}
{% set text_bill = raw_bill | string | replace('<br>', '\n') | replace('<br/>', '\n') | replace('<br />', '\n') | striptags %}
{% set ns_bill = namespace(lines=[]) %}
{% for line in text_bill.splitlines() %}
  {% set cl = line.strip().strip(',') %}
  {% if cl %}{% set _ = ns_bill.lines.append(cl) %}{% endif %}
{% endfor %}
{% set billing_address_compact = ns_bill.lines | join(', ') %}

<!-- 3. CLEAN SHIPPING ADDRESS -->
{% set raw_ship = (ship_addr_doc.get_display() if ship_addr_doc else '') or doc.shipping_address or doc.address_display or '' %}
{% set text_ship = raw_ship | string | replace('<br>', '\n') | replace('<br/>', '\n') | replace('<br />', '\n') | striptags %}
{% set ns_ship = namespace(lines=[]) %}
{% for line in text_ship.splitlines() %}
  {% set cl = line.strip().strip(',') %}
  {% if cl %}{% set _ = ns_ship.lines.append(cl) %}{% endif %}
{% endfor %}
{% set shipping_address_compact = ns_ship.lines | join(', ') %}

<!-- ============================================== -->

{% set place_supply_display = (billing_addr_doc.get('state') if billing_addr_doc else '') or (doc.get('place_of_supply') or '') %}
{% set _po_gc = frappe.db.sql("SELECT GROUP_CONCAT(DISTINCT purchase_order SEPARATOR ', ') FROM `tabSales Order Item` WHERE parent=%s AND IFNULL(purchase_order,'') != ''", doc.name) %}
{% set po_linked = (_po_gc[0][0] if _po_gc and _po_gc[0] and _po_gc[0][0] else '') %}
{% set po_display = po_linked or (doc.get('inter_company_order_reference') or '') or (doc.po_no or '') %}
{% set site_name_obm = frappe.db.get_value('Offline Buyer Master', doc.custom_offline_buyer_master, 'site_name') if doc.get('custom_offline_buyer_master') else '' %}
{% set obm_doc = frappe.get_doc('Offline Buyer Master', doc.custom_offline_buyer_master) if doc.get('custom_offline_buyer_master') else None %}
{% set company_gst = '24AASCA1881A1ZV' %}

{% set freebies = doc.custom_marketing_freebies or [] %}
{% set total_qty = doc.total_qty or 0 %}

<style>
  @page { size: A4; margin: 10mm; }
  .so-wrap { font-family: Arial, sans-serif; color: #000; font-size: 11px; width: 100%; }

  /* THE GLOBAL ANTI-SPLIT LOCK */
  .so-table { 
    width: 100%; 
    border-collapse: collapse; 
    table-layout: fixed; 
    margin-bottom: -1px; 
    page-break-inside: avoid !important; 
    break-inside: avoid !important; 
  }
  .so-table tr {
    page-break-inside: avoid !important; 
    break-inside: avoid !important; 
  }

  .so-table td, .so-table th { border: 1px solid #000; padding: 6px 8px; vertical-align: top; line-height: 1.4; word-wrap: break-word; overflow: visible !important; }

  /* TABLE-PER-ROW BORDER ALIGNMENT */
  .row-table {
    margin-top: -1px !important;
    margin-bottom: 0 !important;
  }
  .header-table {
    margin-bottom: 0 !important;
    page-break-after: avoid !important;
  }

  .so-main-title { font-size: 24px; font-weight: 800; letter-spacing: 0.5px; padding: 8px 0 10px; }
  .center { text-align: center; }
  .left { text-align: left; }
  .right { text-align: right; }
  .bold { font-weight: 800; }
  .mt12 { margin-top: 12px; }

  .bg-grey { background-color: #fcfcfc; }
  .cell-label { font-weight: 800; display: block; margin-bottom: 2px; color: #000; font-size: 10px; text-transform: uppercase; }

  /* Column widths */
  .col-sr { width: 5%; } .col-img { width: 9%; } .col-sku { width: 27%; } .col-qty { width: 8%; } 
  .col-uom { width: 8%; } .col-mrp { width: 10%; } .col-flat { width: 8%; } .col-offer { width: 8%; } .col-amt { width: 17%; }
</style>

<div class='so-wrap'>
  <div class='so-main-title center'>SALES ORDER</div>

  <!-- Header Table -->
  <table class='so-table'>
    <colgroup><col style='width:18%'><col style='width:32%'><col style='width:25%'><col style='width:25%'></colgroup>
    <tr>
      <td rowspan='2' class='center' style='vertical-align:middle; padding: 10px;'>
        {% if company and company.company_logo %}<img src='{{ frappe.utils.get_url(company.company_logo) }}' alt='' style='max-height:68px; max-width:100%;'>{% else %}LOGO{% endif %}
      </td>
      <td class='left' style='font-size: 15px; padding: 12px 8px; font-weight: 800;'>{{ company.company_name if company else '' }}</td>
      <td style='background-color: #f7f7f7;'><span class='bold' style='color: #000; font-size: 10px; text-transform: uppercase;'>Sales Order #</span><br><span style='font-size: 14px; font-weight: 800; color: #000;'>{{ doc.name }}</span></td>
      <td style='background-color: #f7f7f7;'><span class='bold' style='color: #000; font-size: 10px; text-transform: uppercase;'>Sales Date</span><br><span style='font-size: 13px; font-weight: 800; color: #000;'>{{ frappe.utils.formatdate(doc.transaction_date, 'dd-mm-yyyy') if doc.transaction_date else '' }}</span></td>
    </tr>
    <tr>
      <td class='left' style='padding: 8px 8px;'>
        <div style="margin-bottom:2px;"><span class='bold' style="color:#000;">GSTIN:</span> <span style="font-weight:700;">{{ company_gst }}</span></div>
        {% if company and company.phone_no %}<div style="margin-bottom:2px;"><span class='bold' style="color:#000;">Phone:</span> <span style="font-weight:600;">{{ company.phone_no }}</span></div>{% endif %}
        {% if company and company.email %}<div style="margin-bottom:2px;"><span class='bold' style="color:#000;">Email:</span> <span style="font-weight:600;">{{ company.email }}</span></div>{% endif %}
        {% if company and company.website %}<div><span class='bold' style="color:#000;">Website:</span> <span style="font-weight:600;">{{ company.website.replace('https://','').replace('http://','') }}</span></div>{% endif %}
      </td>
      <td><span class='bold' style='color: #000; font-size: 10px; text-transform: uppercase;'>Place of Supply</span><br><span style='font-size: 12px; font-weight: 700;'>{{ place_supply_display }}</span></td>
      <td><span class='bold' style='color: #000; font-size: 10px; text-transform: uppercase;'>PO#</span><br><span style='font-size: 12px; font-weight: 700;'>{{ po_display }}</span></td>
    </tr>
    <tr>
      <td colspan='2' style='padding: 8px 8px; line-height: 1.3;'>
        <div style="margin-bottom:3px;"><span class='bold' style='color: #000; font-size: 10px; text-transform: uppercase;'>Company Address</span></div>
        <div style="font-weight: 500; color: #111;">{{ company_address_compact }}</div>
      </td>
      <td colspan='2' style='padding: 8px 8px;'>
        <div style="margin-bottom:3px;"><span class='bold' style='color: #000; font-size: 10px; text-transform: uppercase;'>Created By</span></div>
        <div style="font-weight: 700; color: #111;">{{ owner_name }}</div>
      </td>
    </tr>
  </table>

  <!-- Party Table -->
  <table class='so-table mt12'>
    <colgroup>
        <col style='width:25%'>
        <col style='width:25%'>
        <col style='width:50%'>
    </colgroup>
    <tr>
      <td colspan="2" class='bold bg-grey' style="font-size: 12px; color: #000; font-weight: 800;">Order From:</td>
      <td class='bold bg-grey' style="font-size: 12px; color: #000; font-weight: 800;">Ship To:</td>
    </tr>
    <tr>
      <td colspan="2">
        <span class='bold' style='color: #000; font-size: 10px; text-transform: uppercase;'>Buyer Name</span><br>
        <span style="font-weight: 800; font-size: 13px;">{{ doc.customer_name or doc.customer or '' }}</span><br>
        <span class='bold' style='color: #000; font-size: 10px; text-transform: uppercase; margin-top: 6px; display: inline-block;'>Site Name</span><br>
        <span style="font-weight: 700;">{{ site_name_obm or '—' }}</span>
      </td>
      <td style="vertical-align: top;">
        <span class='bold' style='color: #000; font-size: 10px; text-transform: uppercase;'>Name</span><br>
        <span style="font-weight: 800; font-size: 13px;">{{ doc.customer_name or '' }}</span>
      </td>
    </tr>
    <tr>
      <td colspan="2" style="padding: 8px 8px 12px; vertical-align: top; line-height: 1.3;">
          <div style="margin-bottom:3px;"><span class='bold' style='color: #000; font-size: 10px; text-transform: uppercase;'>Buyer Billing Address</span></div>
          <div style="font-weight: 500; color: #111;">{{ billing_address_compact }}</div>
      </td>
      <td rowspan="2" style="vertical-align: top; padding: 8px 8px; line-height: 1.3;">
          <div style="margin-bottom:3px;"><span class='bold' style='color: #000; font-size: 10px; text-transform: uppercase;'>Buyer Shipping Address</span></div>
          <div style="font-weight: 500; color: #111;">{{ shipping_address_compact }}</div>
      </td>
    </tr>
    <tr>
      <td style="padding: 8px; vertical-align: top; line-height: 1.5;">
          <div style="margin-bottom: 2px;"><span class='bold' style='color: #000; font-size: 10px; text-transform: uppercase;'>Phone:</span> <span style="font-weight: 700;">{% if obm_doc and obm_doc.contact_no %}{{ obm_doc.contact_no }}{% elif doc.contact_mobile %}{{ doc.contact_mobile }}{% else %}—{% endif %}</span></div>
          <div><span class='bold' style='color: #000; font-size: 10px; text-transform: uppercase;'>Email:</span> <span style="font-weight: 700; word-break: break-all;">{% if obm_doc and obm_doc.email %}{{ obm_doc.email }}{% elif doc.contact_email %}{{ doc.contact_email }}{% else %}—{% endif %}</span></div>
      </td>
      <td style="padding: 8px; vertical-align: top; line-height: 1.5;">
          {% set display_gst_type = obm_doc.gst_type if obm_doc and obm_doc.gst_type else ('Registered' if doc.tax_id else 'Unregistered') %}
          <div style="margin-bottom: 2px;"><span class='bold' style='color: #000; font-size: 10px; text-transform: uppercase;'>GST Type:</span> <span style="font-weight: 700;">{{ display_gst_type }}</span></div>

          {% set id_label = 'GSTIN' %}
          {% set id_val = '—' %}
          {% if obm_doc %}
             {% if obm_doc.gst_type == 'Registered Business' %}
                {% set id_label = 'GSTIN' %}
                {% set id_val = obm_doc.gst_no %}
             {% else %}
                {% set id_label = 'PAN No.' %}
                {% set id_val = obm_doc.pan_no %}
             {% endif %}
          {% else %}
             {% set id_val = doc.tax_id or '—' %}
          {% endif %}
          <div><span class='bold' style='color: #000; font-size: 10px; text-transform: uppercase;'>{{ id_label }}:</span> <span style="font-weight: 700;">{{ id_val or '—' }}</span></div>
      </td>
    </tr>
  </table>

  <!-- ======================================= -->
  <!-- Items Table (Split Fix Implemented) -->
  <!-- ======================================= -->

  {% set colgroup_items = '<colgroup><col class="col-sr"><col class="col-img"><col class="col-sku"><col class="col-qty"><col class="col-uom"><col class="col-mrp"><col class="col-flat"><col class="col-offer"><col class="col-amt"></colgroup>' %}

  <table class='so-table mt12 header-table'>
    {{ colgroup_items }}
    <thead>
    <tr><th colspan='9' class='center bg-grey' style="font-size: 12px; letter-spacing: 1px; color: #000; font-weight: 800;">ORDER ITEMS</th></tr>
    <tr>
      <th class='center' style="color: #000; font-weight: 800;">Sr.</th>
      <th class='center' style="color: #000; font-weight: 800;">Image</th>
      <th style="color: #000; font-weight: 800;">SKU - SKU Name</th>
      <th class='center' style="color: #000; font-weight: 800;">QTY</th>
      <th class='center' style="color: #000; font-weight: 800;">UOM</th>
      <th class='right' style="color: #000; font-weight: 800;">MRP</th>
      <th class='right' style="color: #000; font-weight: 800;">Flat %</th>
      <th class='right' style="color: #000; font-weight: 800;">Offer %</th>
      <th class='right' style="color: #000; font-weight: 800;">Amount</th>
    </tr>
    </thead>
  </table>

  {% set _amt_ns = namespace(sub=0) %}
  {% for row in doc.items %}
  <table class='so-table row-table'>
    {{ colgroup_items }}
    <tbody>
    <tr>
      <td class='center'>{{ row.idx }}</td>
      <td class='center'>{% if row.custom_product_image %}<img src='{{ frappe.utils.get_url(row.custom_product_image) }}' alt='' style='max-height:50px; max-width:100%;'>{% endif %}</td>
      <td><span style="font-weight: 600;">{{ row.item_code or '' }}</span>{% if row.item_name %} - {{ row.item_name }}{% endif %}</td>
      <td class='center bold'>{{ frappe.utils.fmt_money(row.qty or 0, precision=0).replace('.00','') }}</td>
      <td class='center'>{{ row.uom or '' }}</td>
      <td class='right'>{{ frappe.utils.fmt_money(row.custom_customer_mrp or 0, currency=doc.currency) }}</td>
      <td class='right'>{{ row.custom_flat_discount or 0 }}</td>
      <td class='right'>{{ row.custom_offer or 0 }}</td>
      <td class='right bold'>{% set _mrp = frappe.utils.flt(row.custom_customer_mrp or 0) %}{% set _qty = frappe.utils.flt(row.qty or 0) %}{% set _flatpct = frappe.utils.flt(row.custom_flat_discount or 0) %}{% set _offerpct = frappe.utils.flt(row.custom_offer or 0) %}{% set _list = _mrp * _qty %}{% set _line_amt = frappe.utils.flt(_list * (100 - _flatpct) / 100.0 * (100 - _offerpct) / 100.0) %}{% set _amt_ns.sub = frappe.utils.flt(_amt_ns.sub) + _line_amt %}{{ frappe.utils.fmt_money(_line_amt, currency=doc.currency) }}</td>
    </tr>
    </tbody>
  </table>
  {% endfor %}

  <table class='so-table row-table'>
    {{ colgroup_items }}
    <tbody>
    <tr><td colspan='8' class='right bold'>Sub Total</td><td class='right'>{{ frappe.utils.fmt_money(_amt_ns.sub, currency=doc.currency) }}</td></tr>
    <tr><td colspan='8' class='right bold'>Cash Disc. (INR)</td><td class='right'>{{ frappe.utils.fmt_money(doc.custom_cash_discount_amount or 0, currency=doc.currency) }}</td></tr>
    <tr><td colspan='8' class='right bold' style="font-size: 14px; background-color: #f7f7f7; color: #000; font-weight: 800;">Grand Total</td><td class='right bold' style="font-size: 15px; color: #000; background-color: #f7f7f7;">{{ frappe.utils.fmt_money(doc.grand_total or 0, currency=doc.currency) }}</td></tr>

    </tbody>
  </table>

  <!-- ======================================= -->
  <!-- Marketing Freebies (Split Fix Implemented) -->
  <!-- ======================================= -->

  {% if freebies %}
  {% set colgroup_freebies = '<colgroup><col style="width:10%"><col style="width:35%"><col style="width:10%"><col style="width:45%"></colgroup>' %}
  <table class='so-table mt12 header-table'>
    {{ colgroup_freebies }}
    <thead>
    <tr><th colspan='4' class='center bg-grey' style="font-size: 12px; color: #000; font-weight: 800;">Marketing Freebies</th></tr>
    <tr><th class="center" style="color: #000; font-weight: 800;">Sr.</th><th style="color: #000; font-weight: 800;">SKU - SKU Name</th><th class="center" style="color: #000; font-weight: 800;">QTY</th><th style="color: #000; font-weight: 800;">Remarks</th></tr>
    </thead>
  </table>
  {% for r in freebies %}{% if r.item_code %}
  <table class='so-table row-table'>
    {{ colgroup_freebies }}
    <tbody>
    <tr><td class="center">{{ loop.index }}</td><td><span style="font-weight: 600;">{{ r.item_code or '' }}</span> - {{ r.item_name or '' }}</td><td class='center bold'>{{ r.qty or '' }}</td><td>{{ r.remarks or '' }}</td></tr>
    </tbody>
  </table>
  {% endif %}{% endfor %}
  {% endif %}

  <!-- ======================================= -->
  <!-- Scheme Details (Split Fix Implemented) -->
  <!-- ======================================= -->

  {% set _sch = namespace(show=false) %}
  {% for r in doc.custom_scheme_item_table or [] %}{% if r.item_code %}{% set _sch.show = true %}{% endif %}{% endfor %}
  {% if _sch.show %}
  {% set colgroup_scheme = '<colgroup><col style="width:10%"><col style="width:35%"><col style="width:10%"><col style="width:45%"></colgroup>' %}
  <table class='so-table mt12 header-table'>
    {{ colgroup_scheme }}
    <thead>
    <tr><th colspan='4' class='center bg-grey' style="font-size: 12px; color: #000; font-weight: 800;">Scheme Details</th></tr>
    <tr><th class="center" style="color: #000; font-weight: 800;">Sr.</th><th style="color: #000; font-weight: 800;">SKU - SKU Name</th><th class="center" style="color: #000; font-weight: 800;">QTY</th><th style="color: #000; font-weight: 800;">Scheme</th></tr>
    </thead>
  </table>
  {% set _schn = namespace(n=0) %}
  {% for r in doc.custom_scheme_item_table or [] %}
  {% if r.item_code %}
  {% set _schn.n = _schn.n + 1 %}
  <table class='so-table row-table'>
    {{ colgroup_scheme }}
    <tbody>
    <tr><td class="center">{{ _schn.n }}</td><td><span style="font-weight: 600;">{{ r.item_code or '' }}</span>{% if r.item_name %} - {{ r.item_name }}{% endif %}</td><td class='center bold'>{{ frappe.utils.fmt_money(r.qty or 0, precision=0).replace('.00','') }}</td><td>{{ r.scheme or '' }}</td></tr>
    </tbody>
  </table>
  {% endif %}
  {% endfor %}
  {% endif %}

  <!-- ======================================= -->
  <!-- Additional Details (Split Fix Implemented) -->
  <!-- ======================================= -->

  {% set _dmg = namespace(show=false) %}
  {% for r in doc.custom_additional_units_damage_items or [] %}{% if r.item_code %}{% set _dmg.show = true %}{% endif %}{% endfor %}
  {% if _dmg.show %}
  {% set colgroup_add = '<colgroup><col style="width:8%"><col style="width:28%"><col style="width:10%"><col style="width:22%"><col style="width:32%"></colgroup>' %}
  <table class='so-table mt12 header-table'>
    {{ colgroup_add }}
    <thead>
    <tr><th colspan='5' class='center bg-grey' style="font-size: 12px; color: #000; font-weight: 800;">Additional Details</th></tr>
    <tr><th class="center" style="color: #000; font-weight: 800;">Sr.</th><th style="color: #000; font-weight: 800;">SKU - SKU Name</th><th class="center" style="color: #000; font-weight: 800;">QTY</th><th style="color: #000; font-weight: 800;">Previous Order #</th><th style="color: #000; font-weight: 800;">Remarks</th></tr>
    </thead>
  </table>
  {% set _dn = namespace(n=0) %}
  {% for r in doc.custom_additional_units_damage_items or [] %}
  {% if r.item_code %}
  {% set _dn.n = _dn.n + 1 %}
  <table class='so-table row-table'>
    {{ colgroup_add }}
    <tbody>
    <tr><td class="center">{{ _dn.n }}</td><td><span style="font-weight: 600;">{{ r.item_code or '' }}</span>{% if r.item_name %} - {{ r.item_name }}{% endif %}</td><td class='center bold'>{{ frappe.utils.fmt_money(r.qty or 0, precision=0).replace('.00','') }}</td><td>{{ r.previous_order_id or '' }}</td><td>{{ r.remarks or '' }}</td></tr>
    </tbody>
  </table>
  {% endif %}
  {% endfor %}
  {% endif %}

  <!-- ======================================= -->
  <!-- Final Total PCS Summary -->
  <!-- ======================================= -->
  <table class='so-table mt12'>
    <tr><td class='bold' style='padding:8px; background-color: #fcfcfc; color: #000; font-weight: 800;'>Total PCS: {{ frappe.utils.flt(total_qty, 0) }} ({{ doc.items|length if doc.items else 0 }} Items)</td></tr>
  </table>

  <!-- Final Footer -->
  <table class='so-table mt12'>
    <tr><th colspan='2' class='center bg-grey' style="color: #000; font-weight: 800;">Bank Details</th></tr>
    <tr><td style='width:35%; color: #000; font-weight: 800;' class='bold'>Bank Name</td><td>Axis Bank Ltd.</td></tr>
    <tr><td class='bold' style="color: #000; font-weight: 800;">Branch</td><td>Surat</td></tr>
    <tr><td class='bold' style="color: #000; font-weight: 800;">Account Name</td><td>Alpino Health Foods Pvt. Ltd.</td></tr>
    <tr><td class='bold' style="color: #000; font-weight: 800;">Account Number</td><td>919020040914629</td></tr>
    <tr><td class='bold' style="color: #000; font-weight: 800;">IFSC Code</td><td>UTIB0000047</td></tr>
  </table>

  <table class='so-table mt12'>
    <tr><td class='center'>Subject to Surat Jurisdiction only.</td></tr>
    <tr><td class='center bold' style="font-size: 12px; padding: 12px; color: #000; font-weight: 800;">Thank you for helping making India Protein Sufficient Nation!</td></tr>
  </table>
</div>
